// // This module decrements the 4-bit counter value on every rising edge of the clock and sets the counter to zero when reset is deasserted.
module counter_4bit_async_reset(clk, reset, count);

    input  clk, reset;
    output reg [3:0] count;

    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 0;
        else
            count <= count + 1;
    end

endmodule
